import{_ as n,W as s,X as o,Y as a,$ as c,a2 as h,a0 as r,Z as e,C as d}from"./framework-174e6972.js";const i={},l=r('<h2 id="两种思想的比较" tabindex="-1"><a class="header-anchor" href="#两种思想的比较" aria-hidden="true">#</a> 两种思想的比较</h2><h3 id="面向过程-pop" tabindex="-1"><a class="header-anchor" href="#面向过程-pop" aria-hidden="true">#</a> 面向过程（POP）</h3><p>就是分析出解决问题所需要的步骤，然后用函数把这些步骤一步一步实现，使用的时候一个一个依次调用就可以了，像C语言。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaBase/OOP/202305061005077.png" alt="img" loading="lazy"></p><h3 id="面向对象-oop" tabindex="-1"><a class="header-anchor" href="#面向对象-oop" aria-hidden="true">#</a> 面向对象（OOP）</h3><p>是把构成问题事务分解成各个对象，建立对象的目的不是为了完成一个步骤，而是为了描述某个事物在整个解决问题的步骤中的行为，像c++，c#，java，delphi语言。</p><p><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaBase/OOP/202305061005994.png" alt="img" loading="lazy"></p><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>两种思想可以拿洗衣服举例子。</p><h3 id="面向过程" tabindex="-1"><a class="header-anchor" href="#面向过程" aria-hidden="true">#</a> 面向过程</h3><p>放入衣服 -&gt; 洗衣机开始清洗 -&gt; 洗衣机开始甩干 -&gt; 取出衣服</p><h3 id="面向对象" tabindex="-1"><a class="header-anchor" href="#面向对象" aria-hidden="true">#</a> 面向对象</h3><p>把洗衣服这件拆出来 2个对象</p><p>人 只负责 放衣服和取衣服</p><p>洗衣机 只负责 清洗 和 甩干</p>',15),p={class:"hint-container info"},_=a("p",{class:"hint-container-title"},"提示",-1),u=a("p",null,[a("strong",null,"面向对象的好处"),e("是：一个人 可以对应不同洗衣机 一个洗衣机 也可以 对应 不同的人")],-1),f=a("p",null,[e("从代码上来说就是"),a("strong",null,"提高代码的复用性，解除代码之间的耦合度")],-1);function g(m,O){const t=d("font");return s(),o("div",null,[l,a("div",p,[_,u,f,c(t,{color:"#FF7F24"},{default:h(()=>[e("但是不能说 面向对象就一定比面向过程要好 他们是思想不一样")]),_:1})])])}const P=n(i,[["render",g],["__file","1.OOP-POP.html.vue"]]);export{P as default};
